//! Death #4 — Octonion non-associative routing foundation.
//!
//! Implements the signed Fano basis table from `mulImag` in the Lean
//! ledger (Gnosis/FanoOctonionNonAssoc.lean). Used by the dispatcher
//! to calculate path orientations for α-teleportation jumps.

pub const ORIENTATION_POS: i8 = 1;
pub const ORIENTATION_NEG: i8 = -1;

/// The seven canonical Fano triples: (a, b, c) means e_a * e_b = +e_c.
const FANO_TRIPLES: &[(u8, u8, u8)] = &[
    (1, 2, 3),
    (1, 4, 5),
    (1, 7, 6),
    (2, 4, 6),
    (2, 5, 7),
    (3, 4, 7),
    (3, 6, 5),
];

/// Calculate the product sign of two Fano basis indices e_a * e_b.
///
/// Returns (sign, destination_index).
/// If a == b, returns (0, 0) (nilpotent/identity cases are not used in routing).
/// If a or b is 0 (identity), returns (1, a+b).
pub fn fano_mul(a: u8, b: u8) -> (i8, u8) {
    if a == 0 {
        return (ORIENTATION_POS, b);
    }
    if b == 0 {
        return (ORIENTATION_POS, a);
    }
    if a == b {
        return (0, 0);
    } // In reality e_i^2 = -1, but mesh routing uses basis jumps.

    // Check triples for forward match
    for &(x, y, z) in FANO_TRIPLES {
        if a == x && b == y {
            return (ORIENTATION_POS, z);
        }
        if a == y && b == z {
            return (ORIENTATION_POS, x);
        }
        if a == z && b == x {
            return (ORIENTATION_POS, y);
        }

        // Anti-commutative matches
        if a == y && b == x {
            return (ORIENTATION_NEG, z);
        }
        if a == z && b == y {
            return (ORIENTATION_NEG, x);
        }
        if a == x && b == z {
            return (ORIENTATION_NEG, y);
        }
    }

    (0, 0) // Should not happen for valid Fano indices 1..7
}

/// The associator [a, b, c] = (e_a * e_b) * e_c - e_a * (e_b * e_c).
///
/// In the Octonion mesh, we use this to determine the orientation flip
/// between different AST groupings of the same three contributions.
/// Returns the sign flip relative to the (e_a * e_b) * e_c path.
pub fn fano_associator_sign(a: u8, b: u8, c: u8) -> i8 {
    let (s1, ab) = fano_mul(a, b);
    let (s2, res_left) = fano_mul(ab, c);

    let (s3, bc) = fano_mul(b, c);
    let (s4, res_right) = fano_mul(a, bc);

    if res_left != res_right || res_left == 0 {
        return 0; // Associative or invalid
    }

    if s1 * s2 == s3 * s4 {
        ORIENTATION_POS
    } else {
        ORIENTATION_NEG
    }
}
